// Validate flashcard generation request
const body = $input.first().json.body;

if (!body.user_id || !body.file_id) {
  throw new Error('Missing required fields: user_id, file_id');
}

return [{
  json: {
    user_id: body.user_id,
    file_id: body.file_id,
    num_cards: body.num_cards || 10,
    focus_topics: body.focus_topics || [],
    use_tfidf: body.use_tfidf !== false  // default true
  }
}];

// TF-IDF Topic Extraction + Prepare LLM prompt
const chunks = $input.first().json;
const params = $('Validate: FC Request').first().json;

// Gather all chunks (could be array at top level)
const allChunks = Array.isArray(chunks) ? chunks : [chunks];

if (allChunks.length === 0 || !allChunks[0].content) {
  throw new Error('No content found for the specified file. Please process the file first.');
}

const fullText = allChunks.map(c => c.content).join(' ');
const fileName = allChunks[0].file_name || 'Unknown File';

// =====================================
// TF-IDF Topic Extraction (Lightweight)
// =====================================

// Tokenize and clean
const stopWords = new Set([
  'the','a','an','is','are','was','were','be','been','being','have','has','had',
  'do','does','did','will','would','shall','should','may','might','can','could',
  'in','on','at','to','for','of','with','by','from','as','into','through',
  'and','but','or','nor','not','so','yet','both','either','neither',
  'this','that','these','those','it','its','he','she','they','we','you',
  'his','her','their','our','your','my','me','him','them','us',
  'what','which','who','whom','where','when','why','how',
  'all','each','every','any','some','no','more','most','other','such',
  'than','too','very','just','about','above','after','before','between',
  'also','only','then','there','here','now','up','out','if','because'
]);

const words = fullText.toLowerCase()
  .replace(/[^a-z0-9\s]/g, ' ')
  .split(/\s+/)
  .filter(w => w.length > 3 && !stopWords.has(w) && !/^\d+$/.test(w));

// Calculate Term Frequency
const tf = {};
for (const word of words) {
  tf[word] = (tf[word] || 0) + 1;
}

// Calculate IDF across chunks (each chunk = a document)
const idf = {};
const chunkTexts = allChunks.map(c => c.content.toLowerCase());
const totalDocs = chunkTexts.length;

for (const word of Object.keys(tf)) {
  const docsContaining = chunkTexts.filter(t => t.includes(word)).length;
  idf[word] = Math.log(totalDocs / (docsContaining + 1)) + 1;
}

// Calculate TF-IDF scores
const tfidf = {};
for (const word of Object.keys(tf)) {
  tfidf[word] = (tf[word] / words.length) * idf[word];
}

// Get top topics (bi-gram and single word)
const topTerms = Object.entries(tfidf)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 30)
  .map(([term, score]) => term);

// Extract bigrams for better topic detection
const bigrams = {};
for (let i = 0; i < words.length - 1; i++) {
  const bigram = `${words[i]} ${words[i+1]}`;
  if (!stopWords.has(words[i]) && !stopWords.has(words[i+1])) {
    bigrams[bigram] = (bigrams[bigram] || 0) + 1;
  }
}

const topBigrams = Object.entries(bigrams)
  .filter(([_, count]) => count >= 2)
  .sort((a, b) => b[1] - a[1])
  .slice(0, 15)
  .map(([term]) => term);

const extractedTopics = [...topBigrams, ...topTerms].slice(0, 20);

// =====================================
// Build Flashcard Generation Prompt
// =====================================

// Use first ~6000 chars of text as context (Groq token limits)
const contextText = fullText.substring(0, 6000);

const focusSection = params.focus_topics.length > 0
  ? `\nFOCUS ON THESE TOPICS: ${params.focus_topics.join(', ')}`
  : '';

const prompt = `You are an expert educator creating study flashcards. Generate high-quality Q&A flashcard pairs from the following study material.

STUDY MATERIAL (from "${fileName}"):
${contextText}

KEY TOPICS IDENTIFIED (via TF-IDF analysis):
${extractedTopics.join(', ')}
${focusSection}

GENERATE ${params.num_cards} flashcards. Each flashcard should:
1. Cover a distinct concept, definition, process, or relationship
2. Have a clear, specific question (not too vague)
3. Have a concise but complete answer (2-4 sentences)
4. Be tagged with the relevant topic
5. Include difficulty rating

Respond ONLY with valid JSON in this exact format:
{
  "flashcards": [
    {
      "id": 1,
      "question": "Clear, specific question?",
      "answer": "Concise, accurate answer with key details.",
      "topic": "Topic/concept category",
      "difficulty": "easy|medium|hard",
      "key_terms": ["important", "terms", "in", "this", "card"]
    }
  ],
  "source_topics": ["list of main topics covered"]
}`;

return [{
  json: {
    ...params,
    file_name: fileName,
    extracted_topics: extractedTopics,
    tfidf_top_terms: topTerms.slice(0, 10),
    total_chunks: allChunks.length,
    llm_prompt: prompt
  }
}];

// Parse flashcards from Groq response
const groqResponse = $input.first().json;
const params = $('Extract: TF-IDF Topics').first().json;

let flashcardData;
try {
  const content = groqResponse.choices[0].message.content;
  flashcardData = JSON.parse(content);
} catch (e) {
  throw new Error('Failed to parse flashcards from LLM: ' + e.message);
}

const flashcards = flashcardData.flashcards || [];

// Return individual items for batch storage
const items = flashcards.map((card, idx) => ({
  json: {
    user_id: params.user_id,
    file_id: params.file_id,
    question: card.question,
    answer: card.answer,
    topic: card.topic || 'General',
    difficulty: card.difficulty || 'medium',
    metadata: {
      key_terms: card.key_terms || [],
      card_index: idx,
      file_name: params.file_name,
      source_topics: flashcardData.source_topics || [],
      tfidf_topics: params.tfidf_top_terms
    }
  }
}));

return items;

// Build final response with all flashcards
const storedCards = $input.all();
const params = $('Extract: TF-IDF Topics').first().json;

// Reconstruct flashcard list from stored responses
const flashcards = storedCards.map(item => {
  const data = Array.isArray(item.json) ? item.json[0] : item.json;
  return {
    id: data.id,
    question: data.question,
    answer: data.answer,
    topic: data.topic,
    difficulty: data.difficulty
  };
});

return [{
  json: {
    success: true,
    file_id: params.file_id,
    file_name: params.file_name,
    total_flashcards: flashcards.length,
    extracted_topics: params.extracted_topics,
    tfidf_key_terms: params.tfidf_top_terms,
    flashcards: flashcards,
    generated_at: new Date().toISOString()
  }
}];
